window.ASBAB_NUZUL_CACHE["50"] = {"mapping_ayat":{"50:10":[{"p":"Darimi","n":911,"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ زِيَادِ بْنِ عِلَاقَةَ قَالَ سَمِعْتُ عَمِّي يَقُولُ إِنَّهُ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعَهُ يَقْرَأُ فِي إِحْدَى الرَّكْعَتَيْنِ مِنْ الصُّبْحِ وَالنَّخْلَ بَاسِقَاتٍ قَالَ شُعْبَةُ وَسَأَلْتُهُ مَرَّةً أُخْرَى قَالَ سَمِعْتُهُ يَقْرَأُ بْ ق","trj":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Ziyad bin 'Alqamah] ia berkata; Saya mendengar [Pamanku] berkata, bahwa ia pernah melakukan shalat bersama Nabi shallallahu 'alaihi wasallam. Ia mendengar beliau membaca: 'WAN NAKHLA BAASIQAATIN (dan pohon kurma yang tinggi-tinggi…) (Qs. Qaaf: 10) pada salah satu rakaat shalat Subuh.\" Syu'bah berkata, \"Sekali waktu aku bertanya lagi kepadanya, lalu ia berkata, 'Saya mendengar beliau membaca surat Qaaf.\" "},{"p":"Darimi","n":912,"ar":" أَخْبَرَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ قُطْبَةَ بْنِ مَالِكٍ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْفَجْرِ فِي الرَّكْعَةِ الْأُولَى وَالنَّخْلَ بَاسِقَاتٍ لَهَا طَلْعٌ نَضِيدٌ","trj":"Telah mengabarkan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Ziyad bin 'Alqamah] dari [Quthbah bin Malik] ia berkata, \"Saya mendengar Nabi shallallahu 'alaihi wasallam pada rakaat pertama shalat Subuh membaca: 'WAN NAKHLA BAASIQAATIN LAHAA THAL'UN NADHIID (dan pohon kurma yang tinggi-tinggi yang mempunyai mayang yang bersusun-susun) ' (Qs. Qaaf: 10)."},{"p":"Nasa'i","n":939,"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ وَمُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى وَاللَّفْظُ لَهُ قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ زِيَادِ بْنِ عِلَاقَةَ قَالَ سَمِعْتُ عَمِّي يَقُولُصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ فَقَرَأَ فِي إِحْدَى الرَّكْعَتَيْنِ وَالنَّخْلَ بَاسِقَاتٍ لَهَا طَلْعٌ نَضِيدٌ قَالَ شُعْبَةُ فَلَقِيتُهُ فِي السُّوقِ فِي الزِّحَامِ فَقَالَ ق","trj":"Telah mengabarkan kepada kami [Ismail bin Ma'sud] dan [Muhamad bin Abdul A'la] lafadz ini darinya dia berkata; telah menceritakan kepada kami [Khalid] dan [Syu'bah] dari [Ziyad bin Ilaqah] dia berkata; \"Aku mendengar [pamanku] berkata; \"Aku shalat Subuh bersama Rasulullah Shallallahu'alaihi wasallam, dan beliau Shallallallahu'alaihi wasallam dalam salah satu rakaatnya membaca ayat, Wannakhla Saabiqaatin Lahaa Thal'un Nadhiij ('Dan pohon Kurma yang tinggi-tinggi yang mempunyai mayang yang bersusun). (Qs.Qaaf (50): 10).\" Syu'bah (salah seorang perawi hadits ini) berkata, \"Lalu aku berjumpa dengannya di pasar yang ramai, beliau berkata, 'yang kubaca tadi surat Qaaf.\""}],"50:30":[{"p":"Bukhari","n":5836,"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شَيْبَانُ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَزَالُ جَهَنَّمُ{ تَقُولُ هَلْ مِنْ مَزِيدٍ }حَتَّى يَضَعَ رَبُّ الْعِزَّةِ فِيهَا قَدَمَهُ فَتَقُولُ قَطْ قَطْ وَعِزَّتِكَ وَيُزْوَى بَعْضُهَا إِلَى بَعْضٍرَوَاهُ شُعْبَةُ عَنْ قَتَادَةَ","trj":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syaiban] telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] menuturkan; Nabi shallallahu 'alaihi wasallam bersabda: \"Jahannam tiada henti menuturkan; 'Masihkah ada tambahan? ' (QS. Qaf 30), sampai Allah rabbul 'izzati meletakkan telapak kaki-Nya disana hingga neraka mengatakan; 'Cukup, cukup demi kemuliaan-Mu, ' hingga sebagian penghuni neraka menghimpit sebagian lainnya.\" [Syu'bah] meriwayatkannya dari [Qatadah]."},{"p":"Bukhari","n":6483,"ar":"حَدَّثَنَا ابْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا حَرَمِيٌّ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزَالُ يُلْقَى فِي النَّارِ ح و قَالَ لِي خَلِيفَةُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ وَعَنْ مُعْتَمِرٍ سَمِعْتُ أَبِي عَنْ قَتَادَةَ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزَالُ يُلْقَى فِيهَا{ وَتَقُولُ هَلْ مِنْ مَزِيدٍ }حَتَّى يَضَعَ فِيهَا رَبُّ الْعَالَمِينَ قَدَمَهُ فَيَنْزَوِي بَعْضُهَا إِلَى بَعْضٍ ثُمَّ تَقُولُ قَدْ قَدْ بِعِزَّتِكَ وَكَرَمِكَ وَلَا تَزَالُ الْجَنَّةُ تَفْضُلُ حَتَّى يُنْشِئَ اللَّهُ لَهَا خَلْقًا فَيُسْكِنَهُمْ فَضْلَ الْجَنَّةِ","trj":"Telah menceritakan kepada kami [Ibn Abu Al Aswad] telah menceritakan kepada kami [Harami] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Terus saja -penghuninya- dimasukkan ke dalam Neraka.\" (dalam jalur lain disebutkan) Dan telah berkata kepadaku [Khalifah] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas] dan dari [Mu'tamir] aku mendengar [bapakku] dari [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Terus saja -penghuninya- dimasukkan ke dalam Neraka '(sehingga ia berkata 'Masih adakah tambahan?\" (Qs. Qaaf: 30), hingga Allah Rabbul 'alamin meletakkan telapak kaki-Nya sehingga satu sama lain saling berdesak-desakan, hingga neraka berkata, 'Cukup-cukup' demi kemuliaan dan kehormatan-Mu. Sedangkan surga masih saja terlalu longgar sehingga Allah menciptakan makhluk baru dan meletakkan mereka ke dalam surga yang masih senggang.\""},{"p":"Bukhari","n":6540,"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اخْتَصَمَتْ الْجَنَّةُ وَالنَّارُ إِلَى رَبّهِمَا فَقَالَتْ الْجَنَّةُ يَا رَبِّ مَا لَهَا لَا يَدْخُلُهَا إِلَّا ضُعَفَاءُ النَّاسِ وَسَقَطُهُمْ وَقَالَتْ النَّارُ يَعْنِي أُوثِرْتُ بِالْمُتَكَبِّرِينَ فَقَالَ اللَّهُ تَعَالَى لِلْجَنَّةِ أَنْتِ رَحْمَتِي وَقَالَ لِلنَّارِ أَنْتِ عَذَابِي أُصِيبُ بِكِ مَنْ أَشَاءُ وَلِكُلِّ وَاحِدَةٍ مِنْكُمَا مِلْؤُهَا قَالَ فَأَمَّا الْجَنَّةُ فَإِنَّ اللَّهَ لَا يَظْلِمُ مِنْ خَلْقِهِ أَحَدًا وَإِنَّهُ يُنْشِئُ لِلنَّارِ مَنْ يَشَاءُ فَيُلْقَوْنَ فِيهَا فَ{ تَقُولُ هَلْ مِنْ مَزِيدٍ }ثَلَاثًا حَتَّى يَضَعَ فِيهَا قَدَمَهُ فَتَمْتَلِئُ وَيُرَدُّ بَعْضُهَا إِلَى بَعْضٍ وَتَقُولُ قَطْ قَطْ قَطْ","trj":"Telah menceritakan kepada kami [Ubaidullah bin Sa'd bin Ibrahim] telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [Ayahku] dari [Shalih bin Kisan] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Surga dan neraka saling berselisih kepada Tuhan keduanya, surga berkata, 'Wahai Tuhan, mengapa aku tak dimasuki selain orang-orang lemah dan rakyat jelata? ' Sedang neraka berkata, 'Mengapa aku dikhususkan untuk orang-orang yang sombong? ' Allah ta'ala menjawab surga: \"Engkau adalah rahmat-Ku\", dan Allah berfirman kepada neraka, 'Engkau adalah Siksa-Ku, yang Aku timpakan kepada siapa saja yang Aku kehendaki, dan masing-masing diantara kalian berdua harus dipenuhi.' Nabi bersabda: \"Adapun surga sesungguhnya Allah tidak menzhalimi satupun dari makhluk-Na, dan Allah akan memenuhi neraka dengan siapa saja yang dikehendaki-Nya, lantas mereka dilempar ke dalamnya '(neraka berkata, 'Masihkah ada tambahan) ' (QS. Qaaf ayat: 30) -beliau mengulanginya tiga kali-, kemudian Allah meletakkan telapak kakinya sehingga neraka menjadi penuh, sebagian satu dengan sebagian yang lain saling berhimpitan, neraka pun berkata, 'cukup, cukup, sukup.\""}],"50:38":[{"p":"Bukhari","n":539,"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ حَدَّثَنَا قَيْسٌ قَالَ لِي جَرِيرُ بْنُ عَبْدِ اللَّهِكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ نَظَرَ إِلَى الْقَمَرِ لَيْلَةَ الْبَدْرِ فَقَالَ أَمَا إِنَّكُمْ سَتَرَوْنَ رَبَّكُمْ كَمَا تَرَوْنَ هَذَا لَا تُضَامُّونَ أَوْ لَا تُضَاهُونَ فِي رُؤْيَتِهِ فَإِنْ اسْتَطَعْتُمْ أَنْ لَا تُغْلَبُوا عَلَى صَلَاةٍ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَا فَافْعَلُوا ثُمَّ قَالَ فَ{ سَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَا }","trj":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Isma'il] telah menceritakan kepada kami [Qais], [Jarir bin 'Abdullah] berkata kepadaku, \"Kami sedang bersama Nabi shallallahu 'alaihi wasallam saat beliau melihat rembulan di malam purnama. Kemudian beliau bersabda: \"Sesungguhnya kalian akan melihat Rabb kalian sebagaimana kalian melihat bulan purnama ini. Dan kalian tidak akan saling berdesakan dalam melihatnya. Maka jika kalian mampu untuk tidak terlewatkan melaksanakan shalat sebelum terbit matahari dan sebelum terbenamnya, maka lakukanlah, \" Kemudian beliau membaca: '(Maka bertasbihlah sambil memuji Rabbmu sebelum terbit matahari dan sebelum terbenamnya) ' (Qs. Qaaf: 38)."}],"50:39":[{"p":"Bukhari","n":521,"ar":"حَدَّثَنَا الْحُمَيْدِيُّ قَالَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ قَالَ حَدَّثَنَا إِسْمَاعِيلُ عَنْ قَيْسٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَظَرَ إِلَى الْقَمَرِ لَيْلَةً يَعْنِي الْبَدْرَ فَقَالَ إِنَّكُمْ سَتَرَوْنَ رَبَّكُمْ كَمَا تَرَوْنَ هَذَا الْقَمَرَ لَا تُضَامُّونَ فِي رُؤْيَتِهِ فَإِنْ اسْتَطَعْتُمْ أَنْ لَا تُغْلَبُوا عَلَى صَلَاةٍ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَا فَافْعَلُوا ثُمَّ قَرَأَ{ وَسَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ الْغُرُوبِ }قَالَ إِسْمَاعِيلُ افْعَلُوا لَا تَفُوتَنَّكُمْ","trj":"Telah menceritakan kepada kami [Al Humaidi] berkata, telah menceritakan kepada kami [Marwan bin Mu'awiyah] berkata, telah menceritakan kepada kami [Isma'il] dari [Qais] dari [Jarir bin 'Abdullah] berkata, \"Pada suatu malam kami pernah bersama Nabi shallallahu 'alaihi wasallam, beliau lalu melihat ke arah bulan purnama. Kemudian beliau bersabda: \"Sesungguhnya kalian akan melihat Rabb kalian sebagaimana kalian melihat bulan purnama ini. Dan kalian tidak akan saling berdesakan dalam melihat-Nya. Maka jika kalian mampu untuk tidak terlewatkan untuk melaksanakan shalat sebelum terbit matahri dan sebelum terbenamnya, maka lakukanlah.\" Beliau kemudian membaca ayat: '(Dan bertasbihlah sambil memuji Rabbmu sebelum terbit matahari dan sebelum terbenamnya) ' (Qs. Qaaf: 39). Isma'il menyebutkan, \"Kerjakanlah dan sekali-kali jangan sampai kalian terlewatkan.\""},{"p":"Tirmidzi","n":2407,"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ الْبَجَلِيِّ قَالَكُنَّا جُلُوسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَظَرَ إِلَى الْقَمَرِ لَيْلَةَ الْبَدْرِ فَقَالَ إِنَّكُمْ سَتُعْرَضُونَ عَلَى رَبِّكُمْ فَتَرَوْنَهُ كَمَا تَرَوْنَ هَذَا الْقَمَرَ لَا تُضَامُونَ فِي رُؤْيَتِهِ فَإِنْ اسْتَطَعْتُمْ أَنْ لَا تُغْلَبُوا عَلَى صَلَاةٍ قَبْلَ طُلُوعِ الشَّمْسِ وَصَلَاةٍ قَبْلَ غُرُوبِهَا فَافْعَلُوا ثُمَّ قَرَأَ فَ{ سَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ الْغُرُوبِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Waki'] dari [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Jarir bin Abdullah Al Bajali] berkata: Kami dudu di dekat nabi Shallallahu 'alaihi wa Salam, beliau melihat rembulan di malam purnama lalu bersabda: \"Sesungguhnya kalian akan di hadapkan kepada Rabb kalian, kalian melihatNya seperti kalian melihat rembulan ini, kalian tidak berdesakan dalam melihatNya, karena itu bila kalian mampu untuk tidak dikalahkan shalat sebelum terbitnya matahari dan shalat sebelum terbenamnya matahari, lakukanlah.\" Setelah itu beliau membaca: \"Maka mahasucikanlah Rabbmu sebelum terbitnya matahari dan sebelum tenggelamnya (matahari).\" (QS. Qaf 39), Abu Isa berkata: Hadits ini hasan shahih. "}]},"mapping_surah":[{"p":"Abu Dawud","n":696,"ar":"حَدَّثَنَا أَبُو تَوْبَةَ الرَّبِيعُ بْنُ نَافِعٍ أَخْبَرَنَا أَبُو إِسْحَقَ يَعْنِي الْفَزَارِيَّ عَنْ حُمَيْدٍ عَنْ الْحَسَنِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا نُصَلِّي التَّطَوُّعَ نَدْعُو قِيَامًا وَقُعُودًا وَنُسَبِّحُ رُكُوعًا وَسُجُودًاحَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ حُمَيْدٍ مِثْلَهُ لَمْ يَذْكُرْ التَّطَوُّعَ قَالَ كَانَ الْحَسَنُ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ إِمَامًا أَوْ خَلْفَ إِمَامٍ بِفَاتِحَةِ الْكِتَابِ وَيُسَبِّحُ وَيُكَبِّرُ وَيُهَلِّلُ قَدْرَ ق وَالذَّارِيَاتِ","trj":"Telah menceritakan kepada kami [Abu Taubah Ar Rabi' bin Nafi'] telah mengabarkan kepada kami [Abu Ishaq yaitu Al Fazari] dari [Humaid] dari [Al Hasan] dari [Jabir bin Abdullah] dia berkata: \"Kami shalat sunnah dengan membaca do'a baik ketika berdiri ataupun duduk, dan kami mengucapkan tasbih pada waktu ruku' dan sujud.\" Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Humaid] seperti hadits tersebut dengan tidak menyebutkan shalat sunnah. Humiad berkata; \"Al Hasan membaca Al Fatihah dalam shalat Zhuhur dan Ashar baik ketika menjadi Imam atau di belakang imam dan bertasbih, bertakbir, serta bertahlil sepanjang membaca surat Qaaf dan Adz Dzariyat.\""},{"p":"Abu Dawud","n":914,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ خُبَيْبٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ مَعْنٍ عَنْ بِنْتِ الْحَارِثِ بْنِ النُّعْمَانِ قَالَتْمَا حَفِظْتُ قَافْ إِلَّا مِنْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْطُبُ بِهَا كُلَّ جُمُعَةٍ قَالَتْ وَكَانَ تَنُّورُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَنُّورُنَا وَاحِدًاقَالَ أَبُو دَاوُد قَالَ رَوْحُ بْنُ عُبَادَةَ عَنْ شُعْبَةَ قَالَ بِنْتُ حَارِثَةَ بْنِ النُّعْمَانِ و قَالَ ابْنُ إِسْحَقَ أُمُّ هِشَامٍ بِنْتُ حَارِثَةَ بْنِ النُّعْمَانِ","trj":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syubah] dari [Khubaib] dari [Abdullah bin Muhammad bin Ma'n] dari [Bintu Al Harits bin Nu'man] dia berkata; \"Aku tidak pernah hafal surat Qaaf kecuali langsung dari mulut Rasulullah shallallahu 'alaihi wasallam, sebab beliau selalu berkhutbah dengan surat tersebut setiap hari Jum'at.\" Katanya lagi; \"Dan juga tungku Rasulullah shallallahu 'alaihi wasallam dengan tungku kami menjadi satu.\" Abu Daud berkata; [Rauh bin 'Ubadah] berkata dari [Syu'bah] dia mengatakan; [Bintu Haritsah bin Nu'man] ….\" sedangkan [Ibnu Ishaq] mengatakan; [Ummu Hisyam bintu Haritsah bin Nu'man] …\""},{"p":"Abu Dawud","n":916,"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا مَرْوَانُ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ أُخْتِهَا قَالَتْمَا أَخَذْتُ قَافْ إِلَّا مِنْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَؤُهَا فِي كُلِّ جُمُعَةٍقَالَ أَبُو دَاوُد كَذَا رَوَاهُ يَحْيَى بْنُ أَيُّوبَ وَابْنُ أَبِي الرِّجَالِ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ أُمِّ هِشَامٍ بِنْتِ حَارِثَةَ بْنِ النُّعْمَانِ حَدَّثَنَا ابْنُ السَّرْحِ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يَحْيَى بْنُ أَيُّوبَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ أُخْتٍ لِعَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ كَانَتْ أَكْبَرَ مِنْهَا بِمَعْنَاهُ","trj":"Telah menceritakan kepada kami [Mahmud bin Khalid] telah menceritakan kepada kami [Marwan] telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Yahya bin Sa'id] dari ['Amrah] dari [saudara perempuannya] dia berkata; \"Aku tidak pernah hafal surat Qaaf, kecuali dari mulut Rasulullah shallallahu 'alaihi wasallam, karena beliau membacanya setiap Jum'at.\" Abu Daud berkata; Demikianlah yang di riwayatkan oleh [Yahya bin Ayyub] dan [Ibnu Abu Rijal] dari [Yahya bin Sa'id] dari ['Amrah] dari [Ummu Hisyam binti Haritsah bin Nu'man]. Telah menceritakan kepada kami [Ibnu As Sarh] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yahya bin Ayyub] dari [Yahya bin Sa'id] dari ['Amrah] dari [Saudara perempuannya 'Amrah binti Abdurrahman] bahwa dirinya lebih tua daripada saudara perempuannya dan haditsnya semakna.\""},{"p":"Abu Dawud","n":1085,"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَ سَأَلْتُ عَائِشَةَهَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الضُّحَى فَقَالَتْ لَا إِلَّا أَنْ يَجِيءَ مِنْ مَغِيبِهِ قُلْتُ هَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرِنُ بَيْنَ السُّورَتَيْنِ قَالَتْ مِنْ الْمُفَصَّلِ","trj":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Al Jurairi] dari [Abdullah bin Syaqiq] dia berkata; aku pernah bertanya kepada [Aisyah]; \"Apakah Rasulullah shallallahu 'alaihi wasallam biasa melaksanakan shalat Dhuha?\" Aisyah menjawab; \"tidak, kecuali jika beliau tiba dari suatu perjalanan.\" Tanyaku selanjutnya; \"Apakah beliau juga sering menggabungkan antara dua surat?\" Jawab Aisyah; \"Ya, di surat-surat yang di baca pendek (yaitu dari surat Qaaf atau Al Hujurat sampai surat an nas -pent).\""},{"p":"Abu Dawud","n":1156,"ar":"حَدَّثَنَا مُسَدَّدٌ أَخْبَرَنَا قُرَّانُ بْنُ تَمَّامٍ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ أَخْبَرَنَا أَبُو خَالِدٍ وَهَذَا لَفْظُهُ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَعْلَى عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ أَوْسٍ عَنْ جَدِّهِ قَالَ عَبْدُ اللَّهِ بْنُ سَعِيدٍ فِي حَدِيثِهِ أَوْسُ بْنُ حُذَيْفَةَ قَالَقَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَفْدِ ثَقِيفٍ قَالَ فَنَزَلَتْ الْأَحْلَافُ عَلَى الْمُغِيرَةِ بْنِ شُعْبَةَ وَأَنْزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَنِي مَالِكٍ فِي قُبَّةٍ لَهُ قَالَ مُسَدَّدٌ وَكَانَ فِي الْوَفْدِ الَّذِينَ قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ ثَقِيفٍ قَالَ كَانَ كُلَّ لَيْلَةٍ يَأْتِينَا بَعْدَ الْعِشَاءِ يُحَدِّثُنَا و قَالَ أَبُو سَعِيدٍ قَائِمًا عَلَى رِجْلَيْهِ حَتَّى يُرَاوِحُ بَيْنَ رِجْلَيْهِ مِنْ طُولِ الْقِيَامِ وَأَكْثَرُ مَا يُحَدِّثُنَا مَا لَقِيَ مِنْ قَوْمِهِ مِنْ قُرَيْشٍ ثُمَّ يَقُولُ لَا سَوَاءَ كُنَّا مُسْتَضْعَفِينَ مُسْتَذَلِّينَ قَالَ مُسَدَّدٌ بِمَكَّةَ فَلَمَّا خَرَجْنَا إِلَى الْمَدِينَةِ كَانَتْ سِجَالُ الْحَرْبِ بَيْنَنَا وَبَيْنَهُمْ نُدَالُ عَلَيْهِمْ وَيُدَالُونَ عَلَيْنَا فَلَمَّا كَانَتْ لَيْلَةً أَبْطَأَ عَنْ الْوَقْتِ الَّذِي كَانَ يَأْتِينَا فِيهِ فَقُلْنَا لَقَدْ أَبْطَأْتَ عَنَّا اللَّيْلَةَ قَالَ إِنَّهُ طَرَأَ عَلَيَّ جُزْئِي مِنْ الْقُرْآنِ فَكَرِهْتُ أَنْ أَجِيءَ حَتَّى أُتِمَّهُقَالَ أَوْسٌ سَأَلْتُ أَصْحَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ يُحَزِّبُونَ الْقُرْآنَ قَالُوا ثَلَاثٌ وَخَمْسٌ وَسَبْعٌ وَتِسْعٌ وَإِحْدَى عَشْرَةَ وَثَلَاثَ عَشْرَةَ وَحِزْبُ الْمُفَصَّلِ وَحْدَهُ قَالَ أَبُو دَاوُد وَحَدِيثُ أَبِي سَعِيدٍ أَتَمُّ","trj":"Telah menceritakan kepada kami [Musaddad] telah mengabarkan kepada kami [Qurran bin Tammam]. Dan telah di riwayatkan dari jalur lain, telah menceritakan kepada kami [Abdullah bin Sa'id] telah mengabarkan kepada kami [Abu Khalid], dan ini adalah redaksi dari dia, dari [Abdullah bin Abdurrahman bin Ya'laa] dari [Utsman bin Abdullah bin Aus] dari [kakeknya]. Abdullah bin Sa'id berkata dalam haditsnya Aus bin Hudzaifah, dia berkata; \"Kami mendatangi Rasulullah shallallahu 'alaihi wasallam dalam rombongan delegasi Bani Tsaqif, sekutu-sekutu (aliansi-aliansi) Tsaqif singgah menemui Al-Mughirah bin Syu'bah, sementara Rasulullah shallallahu 'alaihi wasallam memberi persinggahan kepada Bani Malik di tenda besar miliknya. Musaddad berkata dengan redaksi; \"Sedangkan seseorang dari utusan dari Tsaqif yang datang kepada Rasulullah shallallahu 'alaihi wasallam, berkata; \"Setiap habis Isya', beliau selalu menemui kami kami untuk bercakap-cakap.\" Abu Sa'id mengatakan; \"Sambil berdiri di atas salah satu kakinya secara berganti-gantian di antara kedua kakinya, karena lamanya berdiri. Dan yang paling banyak yang diceritakan adalah apa yang beliau alami dari kaumnya, Quraisy. Beliau bersabda: \"Tidaklah sama kami orang-orang yang lemah dan terhina - [Musaddad] berkata- selama kami di Makkah. Ketika kami keluar menuju Madinah, peperangan silih berganti di antara kami dan mereka. Terkadang kami mengalahkan mereka dan terkadang mereka mengalahkan kami.\" Di suatu malam, Beliau terlambat dari kebiasaan waktu kedatangannya kepada kami. Maka aku berkata, \"Anda terlambat datang kepada kami pada malam ini\". Beliau bersabda: \"Sesungguhnya telah datang kepadaku bagian yang aku harus baca dari Al-Qur'an, maka aku tidak senang untuk keluar hingga selesai menyempurnakannya.\" Aus berkata, \"Aku bertanya kepada para sahabat Rasulullah shallallahu 'alaihi wasallam, bagaimanakah kalian membagi-bagi (memilah atau mengelompokkan) dan menertibkan Al-Qur'an? Mereka menjawab: \"Tiga, lima, tujuh, sembilan, sebelas, tigabelas dan bagian surat-surat yang mufashshal (dari surat Qaaf atau al Hujurat sampai an nas).\" Abu Daud berkata; \"Haditsnya Abu Sa'id lebih lengkap.\""},{"p":"Abu Dawud","n":1159,"ar":"حَدَّثَنَا عَبَّادُ بْنُ مُوسَى أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ عَلْقَمَةَ وَالْأَسْوَدِ قَالَاأَتَى ابْنَ مَسْعُودٍ رَجُلٌ فَقَالَ إِنِّي أَقْرَأُ الْمُفَصَّلَ فِي رَكْعَةٍ فَقَالَ أَهَذًّا كَهَذِّ الشِّعْرِ وَنَثْرًا كَنَثْرِ الدَّقَلِ لَكِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ النَّظَائِرَ السُّورَتَيْنِ فِي رَكْعَةٍ النَّجْمَ وَالرَّحْمَنَ فِي رَكْعَةٍ وَاقْتَرَبَتْ وَالْحَاقَّةَ فِي رَكْعَةٍ وَالطُّورَ وَالذَّارِيَاتِ فِي رَكْعَةٍ وَإِذَا وَقَعَتْ وَنُونَ فِي رَكْعَةٍ وَسَأَلَ سَائِلٌ وَالنَّازِعَاتِ فِي رَكْعَةٍ وَوَيْلٌ لِلْمُطَفِّفِينَ وَعَبَسَ فِي رَكْعَةٍ وَالْمُدَّثِّرَ وَالْمُزَّمِّلَ فِي رَكْعَةٍ وَهَلْ أَتَى وَلَا أُقْسِمُ بِيَوْمِ الْقِيَامَةِ فِي رَكْعَةٍ وَعَمَّ يَتَسَاءَلُونَ وَالْمُرْسَلَاتِ فِي رَكْعَةٍ وَالدُّخَانَ وَإِذَا الشَّمْسُ كُوِّرَتْ فِي رَكْعَةٍقَالَ أَبُو دَاوُد هَذَا تَأْلِيفُ ابْنِ مَسْعُودٍ رَحِمَهُ اللَّهُ","trj":"Telah menceritakan kepada kami ['Abbad bin Musa] telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Isra`il] dari [Abu Ishaq] dari ['Alqomah] dan [Al Aswad] keduanya berkata; seorang laki-laki datang kepada [Ibnu Mas'ud] seraya berkata; \"Aku biasa membaca Al Mufashal (dari surat Qaaf atau Al Hujurat sampai an Naas) dalam satu raka'at.\" Maka Ibnu Mas'ud berkata; \"Apakah membaca al Qur'an itu seperti melantunkan sya'ir atau prosa prosa tentang runtuhnya kurma dari pohonnya? Padahal Nabi shallallahu 'alaihi wasallam biasa membaca surat-surat yang sepadan, dua surat dalam satu raka'at, yaitu An Najm dan Ar Rahman dalam satu raka'at.\"Iqtarabat\" dan \"Al Haqqah\" dalam satu raka'at.\"At Thur\" dan \"Adz Dzariyat\" dalam satu raka'at.\"Idza Waqa'at\" dan \"Nuun\" dalam satu raka'at.\"sa`ala saa`ilu\" dan \"wan naazi'aati\" dalam satu raka'at.\"wailul lil muthaffifin\" dan \"abasa\" dalam satu raka'at.\"Al Mudattsir\" dan \"Al Muzammil\" dalam satu raka'at.\"Hal attaa\" dan \"Laa uqsimu bi yaumil Qiyaamah\" dalam satu raka'at.\"Amma yatasaa`alun\" dan \"Wal mursalaati\" dalam satu raka'at.\"Ad dukhaan\" dan \"Idzas syamsu kuwwirat\" dalam satu raka'at.\" Abu Daud berkata; \"Ini adalah tulisan Ibnu Mas'ud rahimahullah.\""},{"p":"Abu Dawud","n":1164,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ بْنِ الْبَرْقِيِّ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا نَافِعُ بْنُ يَزِيدَ عَنْ الْحَارِثِ بْنِ سَعِيدٍ الْعُتَقِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مُنَيْنٍ مِنْ بَنِي عَبْدِ كُلَالٍ عَنْ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْرَأَهُ خَمْسَ عَشْرَةَ سَجْدَةً فِي الْقُرْآنِ مِنْهَا ثَلَاثٌ فِي الْمُفَصَّلِ وَفِي سُورَةِ الْحَجِّ سَجْدَتَانِقَالَ أَبُو دَاوُد رُوِيَ عَنْ أَبِي الدَّرْدَاءِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِحْدَى عَشْرَةَ سَجْدَةً وَإِسْنَادُهُ وَاهٍ","trj":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim bin Al Buraqi] telah menceritakan kepada kami [Ibnu Abu Maryam] telah mengabarkan kepada kami [Nafi' bin Yazid] dari [Al Harits bin Sa'id Al 'Utaqi] dari [Abdullah bin Munain] dari Bani Abdul Kulal, dari ['Amru bin Al 'Ash] bahwa Rasulullah shallallahu 'alaihi wasallam pernah membacakan untuknya lima belas ayat sajadah dalam Al Qur'an, di antaranya tiga ayat terdapat dalam surat Al Mufashal (dari surat Qaaf atau Al Hujurat sampai an naas), dan dalam surat Al Hajj dua ayat sajadah.\" Abu Daud berkata; \"di riwayatkan dari Abu Darda` dari Nabi shallallahu 'alaihi wasallam terdapat sebelas ayat sajadah, sedangkan sanadnya lemah.\""},{"p":"Abu Dawud","n":1166,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَزْهَرُ بْنُ الْقَاسِمِ قَالَ مُحَمَّدٌ رَأَيْتُهُ بِمَكَّةَ حَدَّثَنَا أَبُو قُدَامَةَ عَنْ مَطَرٍ الْوَرَّاقِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَسْجُدْ فِي شَيْءٍ مِنْ الْمُفَصَّلِ مُنْذُ تَحَوَّلَ إِلَى الْمَدِينَةِ","trj":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Azhar bin Al Qasim] -Muhammad mengatakan; \"aku mengetahuinya ketika dia berada di Makkah- telah menceritakan kepada kami [Abu Qudamah] dari [Mathar Al Waraq] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam tidak pernah sujud sama sekali ketika membaca surat Al Mufashal (dari surat Qaaf atau Al Hujurat sampai An Naas) hingga beliau pindah ke Madinah.\""},{"p":"Ahmad","n":918,"ar":"قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الطَّائِفِيُّ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ أَوْسٍ الثَّقَفِيِّ عَنْ جَدِّهِ أَوْسِ بْنِ حُذَيْفَةَ قَالَكُنْتُ فِي الْوَفْدِ الَّذِينَ أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْلَمُوا مِنْ ثَقِيفٍ مِنْ بَنِي مَالِكٍ أَنْزَلَنَا فِي قُبَّةٍ لَهُ فَكَانَ يَخْتَلِفُ إِلَيْنَا بَيْنَ بُيُوتِهِ وَبَيْنَ الْمَسْجِدِ فَإِذَا صَلَّى الْعِشَاءَ الْآخِرَةَ انْصَرَفَ إِلَيْنَا وَلَا نَبْرَحُ حَتَّى يُحَدِّثَنَا وَيَشْتَكِي قُرَيْشًا وَيَشْتَكِي أَهْلَ مَكَّةَ ثُمَّ يَقُولُ لَا سَوَاءَ كُنَّا بِمَكَّةَ مُسْتَذَلِّينَ وَمُسْتَضْعَفِينَ فَلَمَّا خَرَجْنَا إِلَى الْمَدِينَةِ كَانَتْ سِجَالُ الْحَرْبِ عَلَيْنَا وَلَنَا فَمَكَثَ عَنَّا لَيْلَةً لَمْ يَأْتِنَا حَتَّى طَالَ ذَلِكَ عَلَيْنَا بَعْدَ الْعِشَاءِ قَالَ قُلْنَا مَا أَمْكَثَكَ عَنَّا يَا رَسُولَ اللَّهِ قَالَ طَرَأَ عَلَيَّ حِزْبٌ مِنْ الْقُرْآنِ فَأَرَدْتُ أَنْ لَا أَخْرُجَ حَتَّى أَقْضِيَهُ قَالَ فَسَأَلْنَا أَصْحَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَصْبَحْنَا قَالَ قُلْنَا كَيْفَ تُحَزِّبُونَ الْقُرْآنَ قَالُوا نُحَزِّبُهُ ثَلَاثَ سُوَرٍ وَخَمْسَ سُوَرٍ وَسَبْعَ سُوَرٍ وَتِسْعَ سُوَرٍ وَإِحْدَى عَشْرَةَ سُورَةً وَثَلَاثَ عَشْرَةَ سُورَةً وَحِزْبَ الْمُفَصَّلِ مِنْ قَافْ حَتَّى يُخْتَمَ","trj":"(Ahmad bin hanbal) berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Abdullah bin Abdurrahman Ath-Tha'ifi] dari ['Utsman bin Abdullah bin Aus Ats-Tsaqafi] dari [kakeknya, Aus bin Hudzaifah] berkata; saya berada dalam rombongan utusan yang mendatangi Nabi Shallallahu'alaihiwasallam. Mereka telah masuk Islam, dari kabilah tsaqif Tsaqif, dari Bani Malik. Kami mendatangi kemah besar beliau, yang kemah tersebut berada antara rumahnya dan masjid. Jika beliau telah melaksanakan shalat isya' pada akhir malam, beliau mengunjungi kami, dan kami tidak meninggalkan tempat itu sampai beliau menceritakan kepada kami dan mengadukan penderitaannya dari orang Quraisy dan penduduk Makkah. Selanjutnya beliau bersabda: \"Tidak sama, kami di Makkah dalam keadaan selalu dihinakan dan dilemahkan. Tatkala kami keluar ke Madinah, terjadilah peperangan, Kemenangan dan kekalahan terjadi silih berganti, terkadang kami menerima kekalahan, namun terkadang memperoleh kemenangan\". Suatu malam beliau tidak mendatangi kami, hal itu berlalu sekian lama sesudah waktu isya'. (Aus bin Hudzaifah) berkata; apa yang menyebabkan anda meninggalkan kami Wahai Rasulullah? Beliau bersabda: \"Telah turun kepadaku sekian kumpulan alqur'an, sehingga memaksa saya tidak keluar sampai hal itu selesai. (Aus bin Hudzaifah) berkata; kami bertanya kepada para sahabat Rasulullah Shallallahu'alaihiwasallam pada pagi harinya. Bagaimana kalian membagi pengelompokan Al qur'an?, mereka menjawab, kami membaginya menjadi tiga surat, lima surat, tujuh surat, sembilan surat, sebelas surat, tiga belas surat, dan hizb Al mufashshal yaitu dari surat QAF sampai akhir."},{"p":"Ahmad","n":2319,"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الطَّائِفِيُّ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ أَوْسٍ الثَّقَفِيِّ عَنْ جَدِّهِ أَوْسِ بْنِ حُذَيْفَةَ قَالَكُنْتُ فِي الْوَفْدِ الَّذِينَ أَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْلَمُوا مِنْ ثَقِيفٍ مِنْ بَنِي مَالِكٍ أَنْزَلَنَا فِي قُبَّةٍ لَهُ فَكَانَ يَخْتَلِفُ إِلَيْنَا بَيْنَ بُيُوتِهِ وَبَيْنَ الْمَسْجِدِ فَإِذَا صَلَّى الْعِشَاءَ الْآخِرَةَ انْصَرَفَ إِلَيْنَا فَلَا يَبْرَحُ يُحَدِّثُنَا وَيَشْتَكِي قُرَيْشًا وَيَشْتَكِي أَهْلَ مَكَّةَ ثُم��َ يَقُولُ لَا سَوَاءَ كُنَّا بِمَكَّةَ مُسْتَذَلِّينَ أَوْ مُسْتَضْعَفِينَ فَلَمَّا خَرَجْنَا إِلَى الْمَدِينَةِ كَانَتْ سِجَالُ الْحَرْبِ عَلَيْنَا وَلَنَا فَمَكَثَ عَنَّا لَيْلَةً لَمْ يَأْتِنَا حَتَّى طَالَ ذَلِكَ عَلَيْنَا بَعْدَ الْعِشَاءِ قَالَ قُلْنَا مَا أَمْكَثَكَ عَنَّا يَا رَسُولَ اللَّهِ قَالَ طَرَأَ عَنِّي حِزْبٌ مِنْ الْقُرْآنِ فَأَرَدْتُ أَنْ لَا أَخْرُجَ حَتَّى أَقْضِيَهُ فَسَأَلْنَا أَصْحَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَصْبَحْنَا قَالَ قُلْنَا كَيْفَ تُحَزِّبُونَ الْقُرْآنَ قَالُوا نُحَزِّبُهُ سِتَّ سُوَرٍ وَخَمْسَ سُوَرٍ وَسَبْعَ سُوَرٍ وَتِسْعَ سُوَرٍ وَإِحْدَى عَشْرَةَ سُورَةً وَثَلَاثَ عَشْرَةَ سُورَةً وَحِزْبُ الْمُفَصَّلِ مِنْ ق حَتَّى تَخْتِمَ","trj":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] Telah menceritakan kepada kami [Abdullah bin Abdurrahman Ath Thaifi] dari [Utsman bin Abdullah bin Aus Ats Tsaqafi] dari [kakeknya yakni Aus bin Hudzaifah], ia berkata; Saya berada dalam suatu utusan yang menemui Rasulullah shallallahu 'alaihi wasallam dan menyatakan masuk Islam. Mereka adalah Bani Tsaqif dari Bani Malik. Kami singgah di sebuah kemah milik beliau. Beliau seringkali mendatangi kami yang berada antara rumah beliau dan masjid. Jika beliau selesai shalat isyak (yaitu shalat fardhu terakhir), beliau sering menemui kami, mengajak kami berbincang-bincang dan mengeluhkan quraisy dan juga penduduk Makkah. Kemudian beliau bersabda \"Terus terang tidak sama nasib kita, kita di Makkah dalam keadaan terintimidasi, atau tertindas, ada pun setelah kita mengungsi ke Madinah, keadaan peperangan silih berganti. Terkadang kita yang kalah, dan tak jarang terkadang kita yang menang. Suatu malam beliau tidak menemui sekian lama sehabis isyak. Kata Aus, kami mencoba bertanya \"Wahai rasulullah, apa yang menghalangimu tidak menemui kami? Beliau menjawab \" Maaf, pengelompokan alquran harus kukerjakan, sehingga aku tak bisa pergi hingga aku menyelesaikannya. Pagi harinya kami bertanya sahabat-sahabat Rasulullah, bagaimana kalian mengelompokkan alquran? Mereka jawab \"Kami mengelompokkannya enam surat, lima surat, tujuh surat, Sembilan surat, sebelas surat, tiga belas surat, dan satu hizib (kelompok) yang berisi surat-surat pendek, semenjak surat Qaf hingga khatam."},{"p":"Ahmad","n":3098,"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا مَالِكٌ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِأَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ سَأَلَ أَبَا وَاقِدٍ اللَّيْثِيَّ بِمَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْعِيدِ قَالَ كَانَ يَقْرَأُ بِقَافْ وَ اقْتَرَبَتْ","trj":"Telah bercerita kepada kami ['Abdur Rahman bin Mahdi] telah bercerita kepada kami [Malik] dari [Dhamrah bin Sa'id] dari [Ubaidillah bin Abdullah] bahwa Umar bin Al Khaththab Radliyallahu'anhu bertanya kepada [Abu Waqid Al Laitsi] apa yang dibaca Rasulullah Shallallahu'alaihiwasallam saat shalat 'id. Ia menjawab: Beliau membaca surat qaaf dan iqtarabat (Alqamar)."},{"p":"Ahmad","n":4222,"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ ابْنِ أَخِي عَمْرَةَ سَمِعْتُهُ مِنْهُ قَبْلَ أَنْ يَجِيءَ الزُّهْرِيُّ عَنْ امْرَأَةٍ مِنَ الْأَنْصَارِ قَالَتْكَانَ تَنُّورُنَا وَتَنُّورُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحِدًا فَمَا حَفِظْتُ ق إِلَّا مِنْهُ كَانَ يَقْرَؤُهَا","trj":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Muhammad bin 'Abdurrahman bin Sa'd bin Zurarah] anak laki-laki saudara 'Amrah -aku mendengar darinya sebelum kedatangan Az Zuhri-, dari [seorang wanita Anshar] dia berkata, \"Tungku masakku bergabung dengan tungku masak Nabi shallallahu 'alaihi wasallam, sehingga aku tidak hafal surat Qaaf kecuali darinya yang beliau bacakan.\""},{"p":"Ahmad","n":4223,"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ عَنْ أُمِّ هِشَامٍ بِنْتِ حَارِثَةَ قَالَتْلَقَدْ كَانَ تَنُّورُنَا وَتَنُّورُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحِدًا سَنَتَيْنِ أَوْ سَنَةً وَبَعْضَ سَنَةٍ وَمَا أَخَذْتُ ق وَالْقُرْآنِ الْمَجِيدِ إِلَّا عَلَى لِسَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ بِهَا كُلَّ يَوْمِ جُمُعَةٍ عَلَى الْمِنْبَرِ إِذَا خَطَبَ النَّاسَ","trj":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] telah menceritakan kepadaku [Abdullah bin Muhammad bin Abu Bakr bin Muhammad bin 'Amru bin Hazm] dari [Yahya bin Abdullah bin 'Abdurrahman bin Sa'ad bin Zurarah] dari [Ummu Hisyam binti Haritsah] dia berkata, \"Dahulu tungku masakku bergabung dengan tungku masak Nabi shallallahu 'alaihi wasallam selama dua tahun, atau satu tahun beberapa bulan, dan tidaklah aku mendapatkan surat 'Qaaf Wal Qur'aanil majiid', kecuali dari lisan Rasulullah shallallahu 'alaihi wasallam yang beliau bacakan setiap hari jumat di atas mimbar saat berkhutbah di hadapan manusia.\""},{"p":"Ahmad","n":4287,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ ثَنَا شُعْبَةُ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ مَعْنٍ عَنِ ابْنَةِ حَارِثَةَ بْنِ النُّعْمَانِ قَالَتْمَا حَفِظْتُ ق إِلَّا مِنْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَخْطُبُ يَوْمَ الْجُمُعَةِ قَالَتْ وَكَانَ تَنُّورُنَا وَتَنُّورُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحِدًا","trj":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Hubaib bin Abdurrahman] dari [Abdullah bin Muhammad bin Ma'n] dari [Anak perempuan Haritsah bin Nu'an] dia berkata, \"Aku hafal surat Qaaf langsung dari Rasulullah shallallahu 'alaihi wasallam sewaktu beliau khutbah Jum'at, dia berkata, \"Karena kompor kami dan kompor Rasulullah shallallahu 'alaihi wasallam itu satu.\""},{"p":"Ahmad","n":4288,"ar":"حَدَّثَنَا الْحَكَمُ بْنُ مُوسَى قَالَ عَبْد اللَّهِ وَسَمِعْتُهُ أَنَا مِنْ الْحَكَمِ قَالَ ثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الرِّجَالِ قَالَ ذَكَرَهُ يَحْيَى بْنُ سَعِيدٍ عَنْ عَمْرَةَ عَنْ أُمِّ هِشَامٍ بِنْتِ حَارِثَةَ بْنِ النُّعْمَانِ قَالَتْمَا أَخَذْتُ ق وَالْقُرْآنِ الْمَجِيدِ إِلَّا مِنْ وَرَاءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بِهَا فِي الصُّبْحِ","trj":"Telah menceritakan kepada kami [Hakam bin Musa] -Abdullah berkata; dan aku telah mendengarnya- dari [Hakam] berkata, telah menceritakan kepada kami [Abdurrahman bin Abu Ar Rijal] berkata, [Yahya bin Sa'id] telah menyebutkan kepadanya dari [Amrah] dari [Ummu Hisyam binti Haritsah bin Nu'man] dia berkata, \"Aku tidak mengambil QAAF WAL QUR'ANIL MAJIID (surat Qaaf) kecuali di belakang Nabi shallallahu 'alaihi wasallam, sewaktu beliau membacanya pada saat shalat subuh.\""},{"p":"Bukhari","n":521,"ar":"حَدَّثَنَا الْحُمَيْدِيُّ قَالَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ قَالَ حَدَّثَنَا إِسْمَاعِيلُ عَنْ قَيْسٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَظَرَ إِلَى الْقَمَرِ لَيْلَةً يَعْنِي الْبَدْرَ فَقَالَ إِنَّكُمْ سَتَرَوْنَ رَبَّكُمْ كَمَا تَرَوْنَ هَذَا الْقَمَرَ لَا تُضَامُّونَ فِي رُؤْيَتِهِ فَإِنْ اسْتَطَعْتُمْ أَنْ لَا تُغْلَبُوا عَلَى صَلَاةٍ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَا فَافْعَلُوا ثُمَّ قَرَأَ{ وَسَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ الْغُرُوبِ }قَالَ إِسْمَاعِيلُ افْعَلُوا لَا تَفُوتَنَّكُمْ","trj":"Telah menceritakan kepada kami [Al Humaidi] berkata, telah menceritakan kepada kami [Marwan bin Mu'awiyah] berkata, telah menceritakan kepada kami [Isma'il] dari [Qais] dari [Jarir bin 'Abdullah] berkata, \"Pada suatu malam kami pernah bersama Nabi shallallahu 'alaihi wasallam, beliau lalu melihat ke arah bulan purnama. Kemudian beliau bersabda: \"Sesungguhnya kalian akan melihat Rabb kalian sebagaimana kalian melihat bulan purnama ini. Dan kalian tidak akan saling berdesakan dalam melihat-Nya. Maka jika kalian mampu untuk tidak terlewatkan untuk melaksanakan shalat sebelum terbit matahri dan sebelum terbenamnya, maka lakukanlah.\" Beliau kemudian membaca ayat: '(Dan bertasbihlah sambil memuji Rabbmu sebelum terbit matahari dan sebelum terbenamnya) ' (Qs. Qaaf: 39). Isma'il menyebutkan, \"Kerjakanlah dan sekali-kali jangan sampai kalian terlewatkan.\""},{"p":"Bukhari","n":539,"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ حَدَّثَنَا قَيْسٌ قَالَ لِي جَرِيرُ بْنُ عَبْدِ اللَّهِكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ نَظَرَ إِلَى الْقَمَرِ لَيْلَةَ الْبَدْرِ فَقَالَ أَمَا إِنَّكُمْ سَتَرَوْنَ رَبَّكُمْ كَمَا تَرَوْنَ هَذَا لَا تُضَامُّونَ أَوْ لَا تُضَاهُونَ فِي رُؤْيَتِهِ فَإِنْ اسْتَطَعْتُمْ أَنْ لَا تُغْلَبُوا عَلَى صَلَاةٍ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَا فَافْعَلُوا ثُمَّ قَالَ فَ{ سَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَا }","trj":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Isma'il] telah menceritakan kepada kami [Qais], [Jarir bin 'Abdullah] berkata kepadaku, \"Kami sedang bersama Nabi shallallahu 'alaihi wasallam saat beliau melihat rembulan di malam purnama. Kemudian beliau bersabda: \"Sesungguhnya kalian akan melihat Rabb kalian sebagaimana kalian melihat bulan purnama ini. Dan kalian tidak akan saling berdesakan dalam melihatnya. Maka jika kalian mampu untuk tidak terlewatkan melaksanakan shalat sebelum terbit matahari dan sebelum terbenamnya, maka lakukanlah, \" Kemudian beliau membaca: '(Maka bertasbihlah sambil memuji Rabbmu sebelum terbit matahari dan sebelum terbenamnya) ' (Qs. Qaaf: 38)."},{"p":"Bukhari","n":5836,"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شَيْبَانُ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَزَالُ جَهَنَّمُ{ تَقُولُ هَلْ مِنْ مَزِيدٍ }حَتَّى يَضَعَ رَبُّ الْعِزَّةِ فِيهَا قَدَمَهُ فَتَقُولُ قَطْ قَطْ وَعِزَّتِكَ وَيُزْوَى بَعْضُهَا إِلَى بَعْضٍرَوَاهُ شُعْبَةُ عَنْ قَتَادَةَ","trj":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syaiban] telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] menuturkan; Nabi shallallahu 'alaihi wasallam bersabda: \"Jahannam tiada henti menuturkan; 'Masihkah ada tambahan? ' (QS. Qaf 30), sampai Allah rabbul 'izzati meletakkan telapak kaki-Nya disana hingga neraka mengatakan; 'Cukup, cukup demi kemuliaan-Mu, ' hingga sebagian penghuni neraka menghimpit sebagian lainnya.\" [Syu'bah] meriwayatkannya dari [Qatadah]."},{"p":"Bukhari","n":6483,"ar":"حَدَّثَنَا ابْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا حَرَمِيٌّ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزَالُ يُلْقَى فِي النَّارِ ح و قَالَ لِي خَلِيفَةُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ وَعَنْ مُعْتَمِرٍ سَمِعْتُ أَبِي عَنْ قَتَادَةَ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزَالُ يُلْقَى فِيهَا{ وَتَقُولُ هَلْ مِنْ مَزِيدٍ }حَتَّى يَضَعَ فِيهَا رَبُّ الْعَالَمِينَ قَدَمَهُ فَيَنْزَوِي بَعْضُهَا إِلَى بَعْضٍ ثُمَّ تَقُولُ قَدْ قَدْ بِعِزَّتِكَ وَكَرَمِكَ وَلَا تَزَالُ الْجَنَّةُ تَفْضُلُ حَتَّى يُنْشِئَ اللَّهُ لَهَا خَلْقًا فَيُسْكِنَهُمْ فَضْلَ الْجَنَّةِ","trj":"Telah menceritakan kepada kami [Ibn Abu Al Aswad] telah menceritakan kepada kami [Harami] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Terus saja -penghuninya- dimasukkan ke dalam Neraka.\" (dalam jalur lain disebutkan) Dan telah berkata kepadaku [Khalifah] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas] dan dari [Mu'tamir] aku mendengar [bapakku] dari [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Terus saja -penghuninya- dimasukkan ke dalam Neraka '(sehingga ia berkata 'Masih adakah tambahan?\" (Qs. Qaaf: 30), hingga Allah Rabbul 'alamin meletakkan telapak kaki-Nya sehingga satu sama lain saling berdesak-desakan, hingga neraka berkata, 'Cukup-cukup' demi kemuliaan dan kehormatan-Mu. Sedangkan surga masih saja terlalu longgar sehingga Allah menciptakan makhluk baru dan meletakkan mereka ke dalam surga yang masih senggang.\""},{"p":"Bukhari","n":6540,"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اخْتَصَمَتْ الْجَنَّةُ وَالنَّارُ إِلَى رَبّهِمَا فَقَالَتْ الْجَنَّةُ يَا رَبِّ مَا لَهَا لَا يَدْخُلُهَا إِلَّا ضُعَفَاءُ النَّاسِ وَسَقَطُهُمْ وَقَالَتْ النَّارُ يَعْنِي أُوثِرْتُ بِالْمُتَكَبِّرِينَ فَقَالَ اللَّهُ تَعَالَى لِلْجَنَّةِ أَنْتِ رَحْمَتِي وَقَالَ لِلنَّارِ أَنْتِ عَذَابِي أُصِيبُ بِكِ مَنْ أَشَاءُ وَلِكُلِّ وَاحِدَةٍ مِنْكُمَا مِلْؤُهَا قَالَ فَأَمَّا الْجَنَّةُ فَإِنَّ اللَّهَ لَا يَظْلِمُ مِنْ خَلْقِهِ أَحَدًا وَإِنَّهُ يُنْشِئُ لِلنَّارِ مَنْ يَشَاءُ فَيُلْقَوْنَ فِيهَا فَ{ تَقُولُ هَلْ مِنْ مَزِيدٍ }ثَلَاثًا حَتَّى يَضَعَ فِيهَا قَدَمَهُ فَتَمْتَلِئُ وَيُرَدُّ بَعْضُهَا إِلَى بَعْضٍ وَتَقُولُ قَطْ قَطْ قَطْ","trj":"Telah menceritakan kepada kami [Ubaidullah bin Sa'd bin Ibrahim] telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [Ayahku] dari [Shalih bin Kisan] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Surga dan neraka saling berselisih kepada Tuhan keduanya, surga berkata, 'Wahai Tuhan, mengapa aku tak dimasuki selain orang-orang lemah dan rakyat jelata? ' Sedang neraka berkata, 'Mengapa aku dikhususkan untuk orang-orang yang sombong? ' Allah ta'ala menjawab surga: \"Engkau adalah rahmat-Ku\", dan Allah berfirman kepada neraka, 'Engkau adalah Siksa-Ku, yang Aku timpakan kepada siapa saja yang Aku kehendaki, dan masing-masing diantara kalian berdua harus dipenuhi.' Nabi bersabda: \"Adapun surga sesungguhnya Allah tidak menzhalimi satupun dari makhluk-Na, dan Allah akan memenuhi neraka dengan siapa saja yang dikehendaki-Nya, lantas mereka dilempar ke dalamnya '(neraka berkata, 'Masihkah ada tambahan) ' (QS. Qaaf ayat: 30) -beliau mengulanginya tiga kali-, kemudian Allah meletakkan telapak kakinya sehingga neraka menjadi penuh, sebagian satu dengan sebagian yang lain saling berhimpitan, neraka pun berkata, 'cukup, cukup, sukup.\""},{"p":"Darimi","n":911,"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ زِيَادِ بْنِ عِلَاقَةَ قَالَ سَمِعْتُ عَمِّي يَقُولُ إِنَّهُ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعَهُ يَقْرَأُ فِي إِحْدَى الرَّكْعَتَيْنِ مِنْ الصُّبْحِ وَالنَّخْلَ بَاسِقَاتٍ قَالَ شُعْبَةُ وَسَأَلْتُهُ مَرَّةً أُخْرَى قَالَ سَمِعْتُهُ يَقْرَأُ بْ ق","trj":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Ziyad bin 'Alqamah] ia berkata; Saya mendengar [Pamanku] berkata, bahwa ia pernah melakukan shalat bersama Nabi shallallahu 'alaihi wasallam. Ia mendengar beliau membaca: 'WAN NAKHLA BAASIQAATIN (dan pohon kurma yang tinggi-tinggi…) (Qs. Qaaf: 10) pada salah satu rakaat shalat Subuh.\" Syu'bah berkata, \"Sekali waktu aku bertanya lagi kepadanya, lalu ia berkata, 'Saya mendengar beliau membaca surat Qaaf.\" "},{"p":"Darimi","n":912,"ar":" أَخْبَرَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ قُطْبَةَ بْنِ مَالِكٍ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْفَجْرِ فِي الرَّكْعَةِ الْأُولَى وَالنَّخْلَ بَاسِقَاتٍ لَهَا طَلْعٌ نَضِيدٌ","trj":"Telah mengabarkan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Ziyad bin 'Alqamah] dari [Quthbah bin Malik] ia berkata, \"Saya mendengar Nabi shallallahu 'alaihi wasallam pada rakaat pertama shalat Subuh membaca: 'WAN NAKHLA BAASIQAATIN LAHAA THAL'UN NADHIID (dan pohon kurma yang tinggi-tinggi yang mempunyai mayang yang bersusun-susun) ' (Qs. Qaaf: 10)."},{"p":"Malik","n":386,"ar":"حَدَّثَنِي يَحْيَى عَنْ مَالِك عَنْ ضَمْرَةَ بْنِ سَعِيدٍ الْمَازِنِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍأَنَّ عُمَرَ بْنَ الْخَطَّابِ سَأَلَ أَبَا وَاقِدٍ اللَّيْثِيَّ مَا كَانَ يَقْرَأُ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْأَضْحَى وَالْفِطْرِ فَقَالَ كَانَ يَقْرَأُ بِ ق وَالْقُرْآنِ الْمَجِيدِ وَاقْتَرَبَتْ السَّاعَةُ وَانْشَقَّ الْقَمَرُ","trj":"Telah menceritakan kepadaku Yahya dari Malik dari [Dlamrah bin Sa'id Al Mazini] dari [Ubaidullah bin Abdullah bin Utbah bin Mas'ud], bahwa Umar bin Khatthab bertanya kepada [Abu Waqid Al Laitsi], tentang apa yang dibaca oleh Rasulullah shallallahu 'alaihi wasallam di hari raya Idul Adlha dan Idul Fitri. Abu Waqid lalu menjawab; \"Beliau membaca surat, 'QAAF, WAL QURANIL MAJID' (surat Qaff) dan 'IQTARABATIS SAA'ATU WANSYAQQAL QAMAR (surat Al Qamar) '.\""},{"p":"Muslim","n":1279,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ الْجُعْفِيُّ عَنْ زَائِدَةَ عَنْ مَنْصُورٍ عَنْ شَقِيقٍ قَالَ جَاءَ رَجُلٌ مِنْ بَنِي بَجِيلَةَ يُقَالُ لَهُ نَهِيكُ بْنُ سِنَانٍ إِلَى عَبْدِ اللَّهِ فَقَالَ إِنِّي أَقْرَأُ الْمُفَصَّلَ فِي رَكْعَةٍ فَقَالَ عَبْدُ اللَّهِ هَذًّا كَهَذِّ الشِّعْرِلَقَدْ عَلِمْتُ النَّظَائِرَ الَّتِي كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِهِنَّ سُورَتَيْنِ فِي رَكْعَةٍ","trj":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Husain bin Ali Al Ju'fi] dari [Za`idah] dari [Manshur] dari [Syaqiq] ia berkata; Seorang laki-laki dari Bani Bajilah yang biada dipanggil Nahik bin Sinan datang menemui [Abdullah] dan berkata, \"Saya membaca Al Mufashshal (surat-surat yang berada di antara surat Qaaf -atau Hujurat- hingga akhir mushhaf) dalam satu raka'at.\" Maka Abdullah pun berkata, \"Engkau membaca seperti cepatnya pembacaan sya'ir. Saya telah mengetahui An Nazha`ir (surat-surat yang hampir sama baik panjangnya atau pun maknanya), yang mana Rasulullah shallallahu 'alaihi wasallam membacanya dua surat pada setiap raka'at.\""},{"p":"Muslim","n":1280,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ أَنَّهُ سَمِعَ أَبَا وَائِلٍ يُحَدِّثُ أَنَّ رَجُلًا جَاءَ إِلَى ابْنِ مَسْعُودٍ فَقَالَ إِنِّي قَرَأْتُ الْمُفَصَّلَ اللَّيْلَةَ كُلَّهُ فِي رَكْعَةٍ فَقَالَ عَبْدُ اللَّهِ هَذًّا كَهَذِّ الشِّعْرِفَقَالَ عَبْدُ اللَّهِ لَقَدْ عَرَفْتُ النَّظَائِرَ الَّتِي كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرُنُ بَيْنَهُنَّ قَالَ فَذَكَرَ عِشْرِينَ سُورَةً مِنْ الْمُفَصَّلِ سُورَتَيْنِ سُورَتَيْنِ فِي كُلِّ رَكْعَةٍ","trj":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] -[Ibnul Mutsanna]- berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Amru bin Murrah] bahwa ia mendengar [Abu wa`il] menceritakan; bahwa seorang laki-laki menemui [Ibnu Mas'ud] seraya berkata, \"Tadi malam saya membaca Al Mufashshal (surat-surat yang berada di antara surat Qaaf -atau Hujurat- hingga akhir mushhaf) seluruhnya dalam satu raka'at.\" Maka Abdullah pun berkata, \"Cepatnya beliau membaca adalah seperti pembacaan sya'ir yang jauh dari ketergesa-gesaan.\" Abdullah berkata; \"Saya telah mengetahui An Nazha`ir (surat-surat yang hampir sama baik panjangnya atau pun maknanya), yang mana Rasulullah shallallahu 'alaihi wasallam membacanya.\" Lalu ia pun menyebutkan dua puluh surat dari Al Mufashshal. Yakni dua surat dua surat pada setiap raka'atnya."},{"p":"Muslim","n":1359,"ar":"و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ أُخْتٍ لِعَمْرَةَ قَالَتْأَخَذْتُ ق وَالْقُرْآنِ الْمَجِيدِ مِنْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْجُمُعَةِ وَهُوَ يَقْرَأُ بِهَا عَلَى الْمِنْبَرِ فِي كُلِّ جُمُعَةٍو حَدَّثَنِيهِ أَبُو الطَّاهِرِ أَخْبَرَنَا ابْنُ وَهْبٍ عَنْ يَحْيَى بْنِ أَيُّوبَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ أُخْتٍ لِعَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ كَانَتْ أَكْبَرَ مِنْهَا بِمِثْلِ حَدِيثِ سُلَيْمَانَ بْنِ بِلَالٍ","trj":"Dan telah menceritakan kepadaku [Abdullah bin Abdurrahman Ad Darimi] telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Yahya bin Sa'id] dari [Amrah binti Abdurrahman] dari [saudara perempuan Amrah], ia berkata, \"Aku menghafal surat Qaaf langsung dari mulut Rasulullah shallallahu 'alaihi wasallam, yakni ketika beliau membacanya beberapa kali di atas mimbar dalam khutbah Jum'at.\" Dan telah menceritakannya kepadaku [Abu Thahir] telah mengabarkan kepada kami [Ibnu Wahb] dari [Yahya bin Ayyub] dari [Yahya bin Sa'id] dari [Amrah] dari [saudara perempuan] Amrah binti Abdurrahman dan lebih besar darinya. yakni sebagaimana hadits Sulaiman bin Bilal."},{"p":"Muslim","n":1360,"ar":"و حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَقَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ الْأَنْصَارِيُّ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ عَنْ أُمِّ هِشَامٍ بِنْتِ حَارِثَةَ بْنِ النُّعْمَانِ قَالَتْلَقَدْ كَانَ تَنُّورُنَا وَتَنُّورُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحِدًا سَنَتَيْنِ أَوْ سَنَةً وَبَعْضَ سَنَةٍ وَمَا أَخَذْتُ ق وَالْقُرْآنِ الْمَجِيدِ إِلَّا عَنْ لِسَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَؤُهَا كُلَّ يَوْمِ جُمُعَةٍ عَلَى الْمِنْبَرِ إِذَا خَطَبَ النَّاسَ","trj":"Dan Telah menceritakan kepada kami [Amru An Naqid] telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'd] telah menceritakan kepada kami [bapakku] dari [Muhammad bin Ishaq] ia berkata, telah menceritakan kepadaku [Abdullah bin Abu Bakar bin Muhammad bin Amru bin Hazm Al Anshari] dari [Yahya bin Abdullah bin Abdurrahman bin Sa'd bin Zurarah] dari [Ummi Hisyam binti Haritsah bin Nu'man] ia berkata, \"Tempat pembuatan roti kami dan tempat pembuatan roti Rasulullah shallallahu 'alaihi wasallam adalah sama selama dua atau satu tahun lebih, dan tidaklah saya menghafal surat 'QAAF WAL QUR`ANIL MAJIID' kecuali dari lisan Rasulullah shallallahu 'alaihi wasallam, beliau membacanya pada setiap hari Jum'at di atas mimbar saat beliau menyampaikan khutbah kepada manusia.\""},{"p":"Muslim","n":1395,"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ الْمَازِنِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِأَنَّ عُمَرَ بْنَ الْخَطَّابِ سَأَلَ أَبَا وَاقِدٍ اللَّيْثِيَّ مَا كَانَ يَقْرَأُ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْأَضْحَى وَالْفِطْرِ فَقَالَ كَانَ يَقْرَأُ فِيهِمَا بِق وَالْقُرْآنِ الْمَجِيدِ وَاقْتَرَبَتْ السَّاعَةُ وَانْشَقَّ الْقَمَرُ","trj":"Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata, saya telah membacakan kepada [Malik] dari [Dlamrah bin Sa'id Al Mazini] dari [Ubaidullah bin Abdullah] bahwasa Umar bin Al Khaththab pernah bertanya kepada [Abu Waqid Al Laitsi], \"Surat apa yang dibaca oleh Rasulullah shallallahu 'alaihi wasallam ketika mengerjakan shalat Iedul Adlha dan Iedul Fithri?\" ia menjawab, \"Beliau membaca surat 'QAAF WAL QUR`ANIL MAJIID' dan 'IQTARABATIS SAA'ATU WAN SYAQQAL QAMAR.'\""},{"p":"Nasa'i","n":938,"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا ابْنُ أَبِي الرِّجَالِ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ أُمِّ هِشَامٍ بِنْتِ حَارِثَةَ بْنِ النُّعْمَانِ قَالَتْمَا أَخَذْتُ ق وَالْقُرْآنِ الْمَجِيدِ إِلَّا مِنْ وَرَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بِهَا فِي الصُّبْحِ","trj":"Telah mengabarkan kepada kami ['Imran bin Yazid] dia berkata; Telah menceritakan kepada kami [Ibnu Abu Rizal] dari [Yahya bin Sa'id] dari ['Amrah] dari [Ummu Hisyam binti Haritsah bin An Nu'man] dia berkata; \"Aku tidaklah menghafal surat Qaaf wal Qur'anil Majiid, kecuali dari belakang Rasulullah Shallallallahu'alaihi wasallam yang pernah beliau baca dalam shalat shubuh.\""},{"p":"Nasa'i","n":939,"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ وَمُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى وَاللَّفْظُ لَهُ قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ زِيَادِ بْنِ عِلَاقَةَ قَالَ سَمِعْتُ عَمِّي يَقُولُصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ فَقَرَأَ فِي إِحْدَى الرَّكْعَتَيْنِ وَالنَّخْلَ بَاسِقَاتٍ لَهَا طَلْعٌ نَضِيدٌ قَالَ شُعْبَةُ فَلَقِيتُهُ فِي السُّوقِ فِي الزِّحَامِ فَقَالَ ق","trj":"Telah mengabarkan kepada kami [Ismail bin Ma'sud] dan [Muhamad bin Abdul A'la] lafadz ini darinya dia berkata; telah menceritakan kepada kami [Khalid] dan [Syu'bah] dari [Ziyad bin Ilaqah] dia berkata; \"Aku mendengar [pamanku] berkata; \"Aku shalat Subuh bersama Rasulullah Shallallahu'alaihi wasallam, dan beliau Shallallallahu'alaihi wasallam dalam salah satu rakaatnya membaca ayat, Wannakhla Saabiqaatin Lahaa Thal'un Nadhiij ('Dan pohon Kurma yang tinggi-tinggi yang mempunyai mayang yang bersusun). (Qs.Qaaf (50): 10).\" Syu'bah (salah seorang perawi hadits ini) berkata, \"Lalu aku berjumpa dengannya di pasar yang ramai, beliau berkata, 'yang kubaca tadi surat Qaaf.\""},{"p":"Nasa'i","n":1385,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا هَارُونُ بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا عَلِيٌّ وَهُوَ ابْنُ الْمُبَارَكِ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ ابْنَةِ حَارِثَةَ بْنِ النُّعْمَانِ قَالَتْحَفِظْتُ ق وَالْقُرْآنِ الْمَجِيدِ مِنْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ يَوْمَ الْجُمُعَةِ","trj":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Harun bin Isma'il] dia berkata; telah menceritakan kepada kami ['Ali bin Al Mubarak] dari [Yahya] dari [Muhammad bin 'Abdurrahman] dari [Bintu Haritsah bin An Nu'man] dia berkata; \"Aku hafal surat Qaaf Wal Qura'anil Majid dari lisan Rasulullah shallallahu 'alaihi wasallam saat itu beliau sedang berada di atas mimbar pada hari Jum'at.\""},{"p":"Nasa'i","n":1517,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا سُفْيَانُ قَالَ حَدَّثَنِي ضَمْرَةُ بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ قَالَخَرَجَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ يَوْمَ عِيدٍ فَسَأَلَ أَبَا وَاقِدٍ اللَّيْثِيَّ بِأَيِّ شَيْءٍ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي هَذَا الْيَوْمِ فَقَالَ بِقَافْ وَاقْتَرَبَتْ","trj":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah memberitakan kepada kami [Sufyan] dia berkata; telah menceritakan kepadaku [Dhamrah bin Sa'id] dari ['Ubaidullah bin 'Abdullah] dia berkata; \"[Umar] radliallahu 'anhu keluar pada hari raya, lalu ia bertanya kepada Abu Waqid AI Laitsi, 'Surat apakah yang dibaca Rasulullah shallallahu 'alaihi wasallam pada hari seperti ini'? ' la menjawab; `Surah Qaaf dan Iqtarobat (Al Qamar) '.\""},{"p":"Tirmidzi","n":490,"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْعِيدَيْنِ وَفِي الْجُمُعَةِ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَهَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ وَرُبَّمَا اجْتَمَعَا فِي يَوْمٍ وَاحِدٍ فَيَقْرَأُ بِهِمَاقَالَ وَفِي الْبَاب عَنْ أَبِي وَاقِدٍ وَسَمُرَةَ بْنِ جُنْدَبٍ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى حَدِيثُ النُّعْمَانِ بْنِ بَشِيرٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَهَكَذَا رَوَى سُفْيَانُ الثَّوْرِيُّ وَمِسْعَرٌ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ نَحْوَ حَدِيثِ أَبِي عَوَانَةَ وَأَمَّا سُفْيَانُ بْنُ عُيَيْنَةَ فَيُخْتَلَفُ عَلَيْهِ فِي الرِّوَايَةِ يُرْوَى عَنْهُ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ أَبِيهِ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ وَلَا نَعْرِفُ لِحَبِيبِ بْنِ سَالِمٍ رِوَايَةً عَنْ أَبِيهِ وَحَبِيبُ بْنُ سَالِمٍ هُوَ مَوْلَى النُّعْمَانِ بْنِ بَشِيرٍ وَرَوَى عَنْ النُّعْمَانِ بْنِ بَشِيرٍ أَحَادِيثَ وَقَدْ رُوِيَ عَنْ ابْنِ عُيَيْنَةَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ نَحْوُ رِوَايَةِ هَؤُلَاءِ وَرُوِي عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقْرَأُ فِي صَلَاةِ الْعِيدَيْنِ بِقَافٍ وَاقْتَرَبَتْ السَّاعَةُ وَبِهِ يَقُولُ الشَّافِعِيُّ","trj":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Ibrahim bin Muhammad bin Al Muntasyir] dari [ayahnya] dari [Habib bin Salim] dari [An Nu'man bin Basyir] dia berkata, Nabi Shallahu 'alaihi wa sallam membaca SABBIHISMA RABBIKA dan HAL ATAAKA HADIITSUL GHAATSIAH pada waktu shalat iedain (dua hari raya) dan shalat Jum'at, jika keduanya terjadi disatu hari, maka belaiu membaca keduanya. (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Abu Wqaqid, Samrah bin Jundab dan Ibnu Abbas. Abu Isa berkata, hadits Nu'man bin Basyir adalah hadits hasan shahih. demikian pula [Sufyan Ats Tsauri] dan [Mis'ar] meriwayatkan dari [Ibrahim bin Muhammad bin Al Muntasyir] seperti hadits yang diriwayatkan Abu 'Awanah. Sedangkan riwayat Sufyan bin 'Uyainah mengenai hal ini masih diperselisihkan, yaitu diriwayatkan dari Ibrahim bin Muhammad bin Al Muntasyir dari ayahnya dari Habib bin Salim dari ayahnya dari Nu'man bin Basyir, akan tetapi kami tidak mengetahui Habib bin Salim memiliki riwayat dari ayahnya. Habib bin Salim adalah budak Nu'man bin Basyir yang banyak meriwayatkan dari Nu'man bin Basyir. Dan diriwayatkan dari [Ibnu Uyainah] dari [Ibrahim bin Muhammad bin Al Muntasyir] seperti riwayat mereka. Diriwayatkan pula dari Nabi shalallahu 'alaihi wa salam bahwa dalam shalat iedain (dua hari raya) beliau membaca surat QAF dan IQTARABATIS SAA'AH. Syafi'i juga berpendapat seperti ini."},{"p":"Tirmidzi","n":524,"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ الْبَزَّازُ الْبَغْدَادِيُّ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا أَبِي عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَسَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا يَعْنِي النَّجْمَ وَالْمُسْلِمُونَ وَالْمُشْرِكُونَ وَالْجِنُّ وَالْإِنْسُقَالَ وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ يَرَوْنَ السُّجُودَ فِي سُورَةِ النَّجْمِ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ لَيْسَ فِي الْمُفَصَّلِ سَجْدَةٌ وَهُوَ قَوْلُ مَالِكِ بْنِ أَنَسٍ وَالْقَوْلُ الْأَوَّلُ أَصَحُّ وَبِهِ يَقُولُ الثَّوْرِيُّ وَابْنُ الْمُبَارَكِ وَالشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ","trj":"Telah menceritakan kepada kami [Harun bin Abdullah Al Bazaz Al Baghdadi] telah menceritakan kepada kami [Abdush Shamad bin Abdul Warits] telah menceritakan kepada kami [ayahku] dari [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas] dia berkata, Rasulullah Sallallahu 'alaihi wasallam sujud tilawah pada surat An Najm, demikian juga kaum muslimin, orang-orang kafir Quraisy, jin dan manusia (Ketika Rasul masih di Makkah. Pent) (perawi) berkata, dalam bab ini (ada juga riwayat -pent) dari Ibnu Mas'ud dan Abu Hurairah. Abu 'Isa berkata, Hadits Ibnu Abbas ialah hadits hasan shahih dan diamalkan oleh ahli ilmu, mereka berpendapat adanya sujud tilawah dalam surat An najm. Sedangkan sebagian ahli ilmu dari para sahabat Nabi shallallahu 'alaihi wasallam berpendapat tidak adanya sujud tilawah pada Al Mufashsal (dari surat Qaf sampai akhir mushaf. Pent) demikian juga pendapat Malik bin Anas. Namun pendapat yang pertama lebih kuat, ini merupakan pendapatnya Ats Tsaury, Ibnu Al Mubarak, Syafi'i, Ahmad dan Ishaq."},{"p":"Tirmidzi","n":547,"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ الْأَعْمَشِ قَال سَمِعْتُ أَبَا وَائِلٍ قَالَسَأَلَ رَجُلٌ عَبْدَ اللَّهِ عَنْ هَذَا الْحَرْفِ{ غَيْرِ آسِنٍ }أَوْ{ يَاسِنٍ }قَالَ كُلَّ الْقُرْآنِ قَرَأْتَ غَيْرَ هَذَا الْحَرْفِ قَالَ نَعَمْ قَالَ إِنَّ قَوْمًا يَقْرَءُونَهُ يَنْثُرُونَهُ نَثْرَ الدَّقَلِ لَا يُجَاوِزُ تَرَاقِيَهُمْ إِنِّي لَأَعْرِفُ السُّوَرَ النَّظَائِرَ الَّتِي كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرُنُ بَيْنَهُنَّ قَالَ فَأَمَرْنَا عَلْقَمَةَ فَسَأَلَهُ فَقَالَ عِشْرُونَ سُورَةً مِنْ الْمُفَصَّلِ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرُنُ بَيْنَ كُلِّ سُورَتَيْنِ فِي رَكْعَةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Daud] dia berkata, telah memberitakan kepada kami [Syu'bah] dari [Al A'masy] dia berkata, saya mendengar [Abu Wa`il] berkata, seorang lelaki bertanya kepada [Abdullah bin Mas'ud] tentang satu kata dalam Al Qur'an yaitu Ghairu aasin atau Ghoiru yaasin, dia (Ibnu Mas'ud) balik bertanya, apakah isi Al Qur'an selain kata ini sudah kau baca semua? Dia menjawab, iya. Lantas (Ibnu Mas'ud) berkata, sesungguhnya ada suatu kaum yang membaca Al Quran tanpa bertadabbur dan tidak menghayatinya, bacaan mereka tidak sampai melewati tenggorokan mereka (tidak masuk ke dalam hati), dan sungguh saya mengetahui surat-surat Al Qur'an yang semisal (baik dalam makna, hukum, peringatan, dan kisah-kisahnya. Pent) yang Rasulullah Shalallahu 'alaihi wa salam sering menggabungkan surat-surat tersebut dalam shalat, Abu wail berkata, lalu kami menyuruh 'Alqamah untuk bertanya, dia (Ibnu Mas'ud) menjawab, Jumlahnya dua puluh surat dari golongan Al Mufashsal (dari surat Qaf sampai akhir surat) Nabi sallallahu 'alaihi wasallam sering membaca dua surat dalam satu raka'at. Abu 'Isa berkata, ini adalah hadits hasan shahih."},{"p":"Tirmidzi","n":2407,"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ الْبَجَلِيِّ قَالَكُنَّا جُلُوسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَظَرَ إِلَى الْقَمَرِ لَيْلَةَ الْبَدْرِ فَقَالَ إِنَّكُمْ سَتُعْرَضُونَ عَلَى رَبِّكُمْ فَتَرَوْنَهُ كَمَا تَرَوْنَ هَذَا الْقَمَرَ لَا تُضَامُونَ فِي رُؤْيَتِهِ فَإِنْ اسْتَطَعْتُمْ أَنْ لَا تُغْلَبُوا عَلَى صَلَاةٍ قَبْلَ طُلُوعِ الشَّمْسِ وَصَلَاةٍ قَبْلَ غُرُوبِهَا فَافْعَلُوا ثُمَّ قَرَأَ فَ{ سَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ الْغُرُوبِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Waki'] dari [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Jarir bin Abdullah Al Bajali] berkata: Kami dudu di dekat nabi Shallallahu 'alaihi wa Salam, beliau melihat rembulan di malam purnama lalu bersabda: \"Sesungguhnya kalian akan di hadapkan kepada Rabb kalian, kalian melihatNya seperti kalian melihat rembulan ini, kalian tidak berdesakan dalam melihatNya, karena itu bila kalian mampu untuk tidak dikalahkan shalat sebelum terbitnya matahari dan shalat sebelum terbenamnya matahari, lakukanlah.\" Setelah itu beliau membaca: \"Maka mahasucikanlah Rabbmu sebelum terbitnya matahari dan sebelum tenggelamnya (matahari).\" (QS. Qaf 39), Abu Isa berkata: Hadits ini hasan shahih. "}]};
